3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  cursed?: boolean;
10	  enchantment?: number;
11	};
12	
13	type Step = {
14	  op: string;
15	  items?: Item[];
16	};
17	
18	type ScenarioInput = {
19	  customer: Customer;
20	  steps: Step[];
21	};
22	
23	type ScenarioOutput = {
24	  results: unknown[];
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	const COMPONENT_BLOCK_SIZE = 3;
33	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
34	
35	const BASE_PREMIUMS: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	  rune: 25,
41	  moonstone: 25,
42	};
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	
46	const isComponentBlock = (type: string, count: number): boolean =>
47	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
48	
49	const curseSurchargeFor = (items: Item[]): number =>
50	  items.reduce(
51	    (surcharge, item) =>
52	      item.cursed
53	        ? surcharge + BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE
54	        : surcharge,
55	    0
56	  );
57	
58	const enchantmentSurchargeFor = (items: Item[]): number =>
59	  items.reduce(
60	    (surcharge, item) =>
61	      (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
62	        ? surcharge + BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
63	        : surcharge,
64	    0
65	  );
66	
67	const basePremiumFor = (items: Item[]): number => {
68	  const countsByType = new Map<string, number>();
69	  for (const item of items) {
70	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
71	  }
72	
73	  let basePremium = curseSurchargeFor(items) + enchantmentSurchargeFor(items);
74	  for (const [type, count] of countsByType) {
75	    basePremium += isComponentBlock(type, count)
76	      ? COMPONENT_BLOCK_BASE_PREMIUM
77	      : count * BASE_PREMIUMS[type];
78	  }
79	  return basePremium;
80	};
81	
82	const quotePremium = (items: Item[]): number => {
83	  const basePremium = basePremiumFor(items);
84	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
85	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
86	};
87	
88	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
89	  const items = input.steps[0].items ?? [];
90	  return { results: [{ premium: quotePremium(items) }] };
91	};
